function setName_(name){
  return name+"_"+Utilities.formatDate(new Date,"GMT","yyyy_MM_dd")
}



function archive(){
  // Get all file and folder
  let spread = SpreadsheetApp.getActive() // get the spreadsheet
  let name = setName_(spread.getSheetName())
  let sheet = spread.duplicateActiveSheet() //get the sheet TVA
  let srange = sheet.getDataRange()
  srange.copyTo(srange, {contentsOnly:true})
  let folder = DriveApp.getFileById(spread.getId()).getParents().next() //get the parent folder of the tcd

  //create new spreadsheet
  let nspread = SpreadsheetApp.create(name)
  //deplace the new sheet to the parent folder 
  DriveApp.getFileById(nspread.getId()).moveTo(folder)

  //copy the sheet to the new spreadsheat 
  sheet.copyTo(nspread).setName(name).getDataRange() 
  nspread.deleteSheet(nspread.getSheets()[0])
  spread.deleteSheet(sheet)
  spread.setActiveSheet(sheet)
}

