//------------------ Balises a remplacer dans le BV ---------------------
const BV_N_CELL = "B2"
const BV_DATE_TODAY_CELL="E2"
const BV_INTERVENANT_NOM_CELL = "H5"
const BV_INTERVENANT_PRENOM_CELL = "H6"
const BV_INTERVENANT_ADRESSE_CELL = "H7"
const BV_INTERVENANT_CP_CELL = "H8"
const BV_INTERVENANT_SS_CELL = "H9"
const BV_INTERVENANT_RM_CELL = "H10"
const BV_INTERVENANT_MISSION_CELL = "H11"
const BV_RET_BRUT_CELL = "E14"
const BV_JEH_CELL = "E15"
const BV_BASE_URSSAF_CELL = "E17"
const BV_TAUX_SS_CELL = "H23"
const BV_TAUX_AT_CELL = "F24"
const BV_PAIEMENT_CELL = "H39"

//------ Colonnes de l'onglet BV & RM --------------------
const BV_SHEET_NAME = "BV & RM"
const BV_COL_N_BV = 2
const BV_COL_REF_ETUDE = BV_COL_N_BV + 1
const BV_COL_DATE_EMISSION = BV_COL_REF_ETUDE + 1
const BV_COL_DATE_PAIEMENT = BV_COL_DATE_EMISSION + 1
const BV_COL_VIREMENT = BV_COL_DATE_PAIEMENT + 1
const BV_COL_MOIS_DECLA = BV_COL_VIREMENT + 1
const BV_COL_NB_JEH = BV_COL_MOIS_DECLA + 1
const BV_COL_RET_BRUT = BV_COL_NB_JEH + 1
const BV_COL_TAUX = BV_COL_RET_BRUT + 1
const BV_COL_NOM_PRENOM = BV_COL_TAUX + 1
const BV_COL_NOM = BV_COL_NOM_PRENOM + 1
const BV_COL_PRENOM = BV_COL_NOM + 1
const BV_COL_N_SS = BV_COL_PRENOM + 1
const BV_COL_ADRESSE_FISCALE = BV_COL_N_SS + 1
const BV_COL_DATE_NAISSANCE = BV_COL_ADRESSE_FISCALE + 2
const BV_COL_RIB = BV_COL_DATE_NAISSANCE + 1
const BV_COL_N_RM = BV_COL_RIB + 1
const BV_COL_N_AVRM = BV_COL_N_RM + 1
const BV_COL_MISSION = BV_COL_N_AVRM + 1
const BV_COL_TAUX_SS = BV_COL_MISSION + 1
const BV_COL_TAUX_AT = BV_COL_TAUX_SS + 1
const BV_COL_BASE_URSSAF = BV_COL_TAUX_AT+1
const BV_COL_ASSIETTE_COTIZ = BV_COL_BASE_URSSAF + 1
const BV_COL_COTIZ_JUNIOR = BV_COL_ASSIETTE_COTIZ + 1
const BV_COL_COTIZ_JUNIOR_ROUND = BV_COL_COTIZ_JUNIOR + 1
const BV_COL_COTIZ_ETU = BV_COL_COTIZ_JUNIOR_ROUND + 1
const BV_COL_TOTAL_COTIZ = BV_COL_COTIZ_ETU + 1
const BV_COL_RET_NET = BV_COL_TOTAL_COTIZ + 1
const BV_COL_RET_BRUT_JEH = BV_COL_RET_NET + 1
const BV_COL_BV = BV_COL_RET_BRUT_JEH + 1
const BV_COL_BQ = BV_COL_BV + 1
const BV_COL_PIECE = BV_COL_BQ + 1
const BV_COL_GENERER_BV = BV_COL_PIECE + 1
//-------- Informations générales l'onglet BV & RM -------------------- 
const BV_SHEET_FIRST_ROW = 8
const BV_SHEET_FIRST_COL = BV_COL_N_BV
const BV_SHEET_LAST_COL = BV_COL_GENERER_BV
//------- Informations a récupérer dans l'onglet Paramétrage
const PARAMETRAGE_SHEET_NAME = "Paramétrage"
const PARAMETRAGE_COL_SITE_NOM = 0
const PARAMETRAGE_COL_SITE_ADD = PARAMETRAGE_COL_SITE_NOM+1
const PARAMETRAGE_COL_SITE_SIRET = PARAMETRAGE_COL_SITE_ADD+1
const PARAMETRAGE_COL_SITE_ID_BV_TYPE = PARAMETRAGE_COL_SITE_SIRET+1
const PARAMETRAGE_COL_SITE_BV_DEST = PARAMETRAGE_COL_SITE_ID_BV_TYPE + 1
const PARAMETRAGE_RANGE = "B28:F28" // /!\ Part du principe qu'il n'y a qu'une Junior car un seul campus

const BV_SHEET_TEMP_NAME ="Fiche BV" // Ne surtout pas changer le nom de la feuille dans le BV Type

/***
 * Fonction qui permet de chercher une balise dans une feuille GSheet et de remplacer par la suite de caratère désirée 
 * @param sheet - SpreadSheet  : feuille dans laquelle faire les remplacements
 * @param searchTerm - string  : balise a remplace
 * @param replacement - string : suite de caratère désirée
 */
function searchAndReplace_(sheet,cell, replacement) {
  // Accède à la cellule spécifiée
  var range = sheet.getRange(cell);

  // Remplace la valeur par la nouvelle
  range.setValue(replacement);  
}

/**
 * Fonction qui génére les BV lorsque la case est coché
 * 
 */
function generate_bv() {
  // Charger les données de la feuille BV & RM
  let ss = SpreadsheetApp.getActive()
  let sheet = ss.getSheetByName(BV_SHEET_NAME)
  let range = sheet.getRange(BV_SHEET_FIRST_ROW,BV_SHEET_FIRST_COL,sheet.getLastRow(),BV_SHEET_LAST_COL)
  let values = range.getValues()

  //Charger les données de la feuille Parametrage pour récupérer les id templates et dossier destination par campus
  let sheet_param = ss.getSheetByName(PARAMETRAGE_SHEET_NAME)
  let range_param = sheet_param.getRange(PARAMETRAGE_RANGE)
  let value_param = range_param.getValues()
  let site_dico = {}

  var junior_name = ""
  if(value_param[0][PARAMETRAGE_COL_SITE_NOM]!=="" && value_param[0][PARAMETRAGE_COL_SITE_ID_BV_TYPE]!=="" && value_param[0][PARAMETRAGE_COL_SITE_BV_DEST]!=="") {
    junior_name = value_param[0][PARAMETRAGE_COL_SITE_NOM]
    site_dico[junior_name] = {
          "bv_type_id":value_param[0][PARAMETRAGE_COL_SITE_ID_BV_TYPE],
          "bv_dossier_dest":value_param[0][PARAMETRAGE_COL_SITE_BV_DEST]
    }
  }

  values.forEach((row,index)=>{
    if(row[BV_COL_GENERER_BV - BV_SHEET_FIRST_COL] == true){
      if(junior_name!==""){
        try{
            //On créer le BV
          let link = createBV(site_dico,row,junior_name)
          // On rempli les infos dans le TS 
          index += BV_SHEET_FIRST_ROW
          let colPiece = BV_COL_PIECE
          let colGen = BV_COL_GENERER_BV
          sheet.getRange(index,colPiece).setValue(link[0]).setShowHyperlink(true)
          sheet.getRange(index,colGen).setValue(false)
        }catch(e){
          console.error(e)
          SpreadsheetApp.getUi().alert(e);
        }
      }
    }
  })
}

/***
 * Fonction qui crée le BV a partir du template dans le bon dossier
 * @param site_dico map<String,String> : maping between key campus and values for BV template and Folder dest
 * @param row  range : row to process
 */

function createBV(site_dico,row,junior_name){
        // On récupère les champs pour le BV
        let bv_n = row[BV_COL_N_BV - BV_SHEET_FIRST_COL]
        let bv_date_today = Utilities.formatDate(row[BV_COL_DATE_EMISSION - BV_SHEET_FIRST_COL], "Europe/Monaco","dd/MM/yyyy")
        Logger.log(bv_date_today)
        let bv_intervenant_nom = row[BV_COL_NOM - BV_SHEET_FIRST_COL]
        let bv_intervenant_prenom = row[BV_COL_PRENOM - BV_SHEET_FIRST_COL]

        let reg = row[BV_COL_ADRESSE_FISCALE - BV_SHEET_FIRST_COL].match("(.*)([0-9]{5,}.*)")
        let bv_intervenant_adresse = row[BV_COL_ADRESSE_FISCALE - BV_SHEET_FIRST_COL]
        if (reg != null){
            bv_intervenant_adresse = reg[1]
            bv_intervenant_cp = reg[2]
        }
        let bv_intervenant_ss = row[BV_COL_N_SS - BV_SHEET_FIRST_COL]
        let bv_intervenant_rm = row[BV_COL_N_RM - BV_SHEET_FIRST_COL]
        let bv_intervenant_avrm = row[BV_COL_N_AVRM - BV_SHEET_FIRST_COL]
        if(bv_intervenant_avrm !=""){
          bv_intervenant_rm += " modifié par "+ bv_intervenant_avrm
        }
        let bv_intervenant_mission = row[BV_COL_MISSION - BV_SHEET_FIRST_COL]

        let bv_virement = row[BV_COL_VIREMENT - BV_SHEET_FIRST_COL]
        let bv_date_paiement = Utilities.formatDate(row[BV_COL_DATE_PAIEMENT- BV_SHEET_FIRST_COL], "Europe/Monaco","dd/MM/yyyy")
        let bv_paiement = "N° " + bv_virement + " le " + bv_date_paiement

        let bv_ret_brut = row[BV_COL_RET_BRUT - BV_SHEET_FIRST_COL]
        let bv_jeh = row[BV_COL_NB_JEH - BV_SHEET_FIRST_COL]
        let bv_base_urssaf = row[BV_COL_BASE_URSSAF - BV_SHEET_FIRST_COL]
        let bv_taux_ss = row[BV_COL_TAUX_SS - BV_SHEET_FIRST_COL]
        let bv_taux_at = row[BV_COL_TAUX_AT - BV_SHEET_FIRST_COL]
        let bv_name = bv_n

        // On récupère les id des template et dossier de destination
        let temp_id = site_dico[junior_name]["bv_type_id"]
        let dest = DriveApp.getFolderById(site_dico[junior_name]["bv_dossier_dest"])
        // On créer le nouveau BV
        let nbv = DriveApp.getFileById(temp_id).makeCopy(bv_name,dest)
        let nsheet= SpreadsheetApp.openById(nbv.getId())
        let nfiche = nsheet.getSheetByName(BV_SHEET_TEMP_NAME)

        // On remplace les balises avec les valeurs du ts
        searchAndReplace_(nfiche,BV_N_CELL,bv_n)
        searchAndReplace_(nfiche,BV_DATE_TODAY_CELL,bv_date_today)
        searchAndReplace_(nfiche,BV_INTERVENANT_NOM_CELL,bv_intervenant_nom)
        searchAndReplace_(nfiche,BV_INTERVENANT_PRENOM_CELL,bv_intervenant_prenom)
        searchAndReplace_(nfiche,BV_INTERVENANT_ADRESSE_CELL,bv_intervenant_adresse)
        searchAndReplace_(nfiche,BV_INTERVENANT_CP_CELL,bv_intervenant_cp)
        searchAndReplace_(nfiche,BV_INTERVENANT_SS_CELL,bv_intervenant_ss)
        searchAndReplace_(nfiche,BV_INTERVENANT_RM_CELL,bv_intervenant_rm)
        searchAndReplace_(nfiche,BV_INTERVENANT_MISSION_CELL,bv_intervenant_mission)
        searchAndReplace_(nfiche,BV_PAIEMENT_CELL,bv_paiement)
        searchAndReplace_(nfiche,BV_RET_BRUT_CELL,Number(bv_ret_brut))
        searchAndReplace_(nfiche,BV_JEH_CELL,Number(bv_jeh))
        searchAndReplace_(nfiche,BV_BASE_URSSAF_CELL,Number(bv_base_urssaf))
        searchAndReplace_(nfiche,BV_TAUX_SS_CELL,Number(bv_taux_ss))
        searchAndReplace_(nfiche,BV_TAUX_AT_CELL,Number(bv_taux_at))
        nfiche.collapseAllColumnGroups()
        //On retourne le lien du BV
        return [nsheet.getUrl(),bv_name]
}

function genererDeclarationTVA() {
  const ui = SpreadsheetApp.getUi();
  const response = ui.prompt("Saisis le mois et l'année de déclaration (ex: Mai 2025)", ui.ButtonSet.OK_CANCEL);

  if (response.getSelectedButton() !== ui.Button.OK) return;
  const moisAnneeCible = response.getResponseText();

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const feuilleAchats = ss.getSheetByName("Factures d'achats");
  const feuilleVentes = ss.getSheetByName("Factures ventes");

  const modeleFileId = ID_TEMPLATE_TVA;
  const dossierId = ID_DOSSIER_TVA;
  const nomNouveauFichier = `TVA ${moisAnneeCible}`;

  const modele = DriveApp.getFileById(modeleFileId);
  const dossier = DriveApp.getFolderById(dossierId);
  const copie = modele.makeCopy(nomNouveauFichier, dossier);
  const newSs = SpreadsheetApp.openById(copie.getId());

  const recapAchats = newSs.getSheetByName("Récap Achats");
  const recapVentes = newSs.getSheetByName("Récap Ventes");

  remplirRecapAchat(feuilleAchats, recapAchats, moisAnneeCible);
  remplirRecapVentes(feuilleVentes, recapVentes, moisAnneeCible);
  insererChipFichier(moisAnneeCible, copie, 11); // colonne K = 11
}

function remplirRecapAchat(sourceSheet, targetSheet, moisAnneeCible) {
  const donnees = sourceSheet.getRange("B8:AB" + sourceSheet.getLastRow()).getValues();

  const numeroMois = {
    "Janvier": 1,
    "Février": 2,
    "Mars": 3,
    "Avril": 4,
    "Mai": 5,
    "Juin": 6,
    "Juillet": 7,
    "Août": 8,
    "Septembre": 9,
    "Octobre": 10,
    "Novembre": 11,
    "Décembre": 12
  };

  const moisCible = moisAnneeCible.split(" ")[0];
  const annnee = parseInt(moisAnneeCible.split(" ")[1], 10);
  const numMoisCible = numeroMois[moisCible];
  if (!numMoisCible) {
    SpreadsheetApp.getUi().alert("Mois invalide. Veuillez saisir un mois valide (ex: Mai 2025).");
    return;
  }
  const moisAnneeCibleLimite = new Date(annnee, numMoisCible - 1 + 1, 0); // Dernier jour du mois cible
  const moisAnneeCibleDebut = new Date(annnee, numMoisCible - 1, 1); // Premier jour du mois cible

  const lignes = [];

  for (const ligne of donnees) {
    const reference = ligne[1];
    if (!reference) continue; // Ignore les lignes sans référence

    let rawDate = ligne[9]; // Colonne K, soit la 9e colonne dans B:AA
    let date;

    if (rawDate === "" || rawDate === null) {
      continue; // Ignore les lignes sans date
    }else if (rawDate instanceof Date) {
      date = rawDate;
    } else if (typeof rawDate === 'string' || typeof rawDate === 'number') {
      date = new Date(rawDate);
    } else {
      // Si vide ou invalide
      continue; // ou : date = null;
    }
    const mois = ligne[10]; // Mois déclaratif de TVA
    const tvaDeclaree = ligne[26]; // TVA déclarée

    if (mois !== moisAnneeCible && (tvaDeclaree === true || date > moisAnneeCibleLimite)) continue; // on ne prend en compte que les lignes du mois cible et celles des mois précédents qui n'ont pas été déclarées

    const tiers = ligne[3];
    const lieuTVAClient = ligne[8];
    const naturePiece = ligne[4];
    if (naturePiece == "Don"|| naturePiece == "Impôt") continue;
    const natureAchat = ligne[5];
    const ht1 = ligne[11];
    const taux1 = ligne[12]
    const tva1 = ligne[13];
    if (ht1 != 0){
      const lignesTVA1 = detecterLignesCA3("ACHAT", lieuTVAClient, natureAchat, date, moisAnneeCibleDebut);

      lignes.push([
        reference, tiers, date, natureAchat,
        taux1,
        ht1, tva1,
        lignesTVA1.ligneHT1, lignesTVA1.ligneHT2, lignesTVA1.ligneTVA1, lignesTVA1.ligneTVA2
      ]);
    }

    const ht2 = ligne[14];
    const taux2 = ligne[15];
    const tva2 = ligne[16];
    if (ht2 != 0){
      const lignesTVA2 = detecterLignesCA3("ACHAT", lieuTVAClient, natureAchat, date, moisAnneeCibleDebut);

      lignes.push([
        reference, tiers, date, natureAchat,
        taux2,
        ht2, tva2,
        lignesTVA2.ligneHT1, lignesTVA2.ligneHT2, lignesTVA2.ligneTVA1, lignesTVA2.ligneTVA2
      ]);
    }

    ligne[26] = true;
    const index = donnees.indexOf(ligne);
    sourceSheet.getRange(index + 8, 27 + 1).setValue(true); // + 8 pour compenser l'indexation de la feuille (commence à 1) et les en-têtes (ligne 7) // + 1 pour compenser l'indexation de la colonne (commence à B)
  }

  if (lignes.length > 0) {
    targetSheet.getRange(2, 1, lignes.length, lignes[0].length).setValues(lignes);
  }
}

function remplirRecapVentes(sourceSheet, targetSheet, moisAnneeCible) {
  // Affiche la colonne S (19)
  const columnGroups = sourceSheet.getColumnGroup(19, 1);

  if (columnGroups) {
    columnGroups.expand(); // Déplie le groupe contenant la colonne S
  }

  const donnees = sourceSheet.getRange("B8:AA" + sourceSheet.getLastRow()).getValues();

  const numeroMois = {
    "Janvier": 1,
    "Février": 2,
    "Mars": 3,
    "Avril": 4,
    "Mai": 5,
    "Juin": 6,
    "Juillet": 7,
    "Août": 8,
    "Septembre": 9,
    "Octobre": 10,
    "Novembre": 11,
    "Décembre": 12
  };
  const moisCible = moisAnneeCible.split(" ")[0];
  const annnee = parseInt(moisAnneeCible.split(" ")[1], 10);
  const numMoisCible = numeroMois[moisCible];
  if (!numMoisCible) {
    SpreadsheetApp.getUi().alert("Mois invalide. Veuillez saisir un mois valide (ex: Mai 2025).");
    return;
  }
  const moisAnneeCibleLimite = new Date(annnee, numMoisCible - 1 + 1, 0); // Dernier jour du mois cible
  const moisAnneeCibleDebut = new Date(annnee, numMoisCible - 1, 1); // Premier jour du mois cible
  const lignes = [];

  for (const ligne of donnees) {
    const reference = ligne[1];
    if (!reference) continue; // Ignore les lignes sans référence
    let rawDate = ligne[20]; // Colonne V, soit la 20e colonne dans B:AA
    let date;
    if (rawDate === "" || rawDate === null) {
      continue; // Ignore les lignes sans date
    }else if (rawDate instanceof Date) {
      date = rawDate;
    } else if (typeof rawDate === 'string' || typeof rawDate === 'number') {
      date = new Date(rawDate);
    } else {
      // Si vide ou invalide
      continue; // ou : date = null;
    }

    const mois = ligne[23]; // Mois déclaratif de TVA
    const tvaDeclaree = ligne[25]; // TVA déclarée
    if (mois !== moisCible && (tvaDeclaree === true || date > moisAnneeCibleLimite)) continue; // on ne prend en compte que les lignes du mois cible et celles des mois précédents qui n'ont pas été déclarées

    const tiers = ligne[2];
    const naturePiece = ligne[3];
    const taux = ligne[17];
    if (taux == 0) {
      SpreadsheetApp.getUi().alert("La ligne " + reference + " a un taux de TVA à 0. Si c'est un client étranger, il faut se renseigner sur KiwiLegal");
      continue;
    }
    const ligneTVA = detecterLignesCA3("VENTE", "", naturePiece, date, moisAnneeCibleDebut);
    const ht =  Math.abs(ligne[16]);
    const tva = Math.abs(ligne[18]);
    if (tva != 0){
      lignes.push([
        reference, tiers, date, naturePiece,
        taux,
        ht, tva,
        ligneTVA.ligneHT1, ligneTVA.ligneHT2, ligneTVA.ligneTVA1, ligneTVA.ligneTVA2
      ]);
    }

    ligne[25] = true;
    const index = donnees.indexOf(ligne);
    sourceSheet.getRange(index + 8, 26 + 1).setValue(true); // + 8 pour compenser l'indexation de la feuille (commence à 1) et les en-têtes (ligne 7) // + 1 pour compenser l'indexation de la colonne (commence à B)
  }
  if (lignes.length > 0) {
    targetSheet.getRange(2, 1, lignes.length, lignes[0].length).setValues(lignes);
  }

  // Remasquer la colonne S
  if (columnGroups) {
    columnGroups.collapse(); // Replie seulement le groupe initial
  }
}


function detecterLignesCA3(type, lieuTVAClient, natureOperation, date, moisAnneeCibleDebut) {
  // Fonction pour détecter les lignes 3310-CA3 en fonction du type d'opération, du lieu de TVA du client, de la nature de l'opération et de la date
  // référence : https://kiwix.junior-entreprises.com/document/document/36584
  const ligne = { "ligneHT1": "", "ligneHT2": "", "ligneTVA1": "", "ligneTVA2": "" };
  if (type === "VENTE") {
    if (natureOperation == "Facture d'Avoir") {
      ligne.ligneHT1 = "B5";
      ligne.ligneTVA1 = "21";
      ligne.ligneTVA2 = "21C";
    } else if (natureOperation == "Subvention NC" || natureOperation == "Cotisation" || natureOperation == "Pro Forma") {
      return ligne;
    } else {
      ligne.ligneHT1 = "A1";
      ligne.ligneHT2 = "08";
    }
  } else if (type === "ACHAT") {
    if (lieuTVAClient === "TVA Intracom") {
      if (natureOperation === "Bien") {
        ligne.ligneHT1 = "B2";
        ligne.ligneHT2 = "08";
        ligne.ligneTVA1 = "17";
        ligne.ligneTVA2 = "20";
      } else if (natureOperation === "Service") {
        ligne.ligneHT1 = "A3";
        ligne.ligneHT2 = "08";
        ligne.ligneTVA1 = "20";
      } else if (natureOperation === "Immobilisation") {
        ligne.ligneHT1 = "B2";
        ligne.ligneHT2 = "08";
        ligne.ligneTVA1 = "17";
        ligne.ligneTVA2 = "19";
      }
    } else if (lieuTVAClient === "TVA Extracom") {
        if (natureOperation === "Bien") {
          ligne.ligneHT1 = "A4";
          ligne.ligneHT2 = "I1";
          ligne.ligneTVA1 = "20";
        } else if (natureOperation === "Service") {
          ligne.ligneHT1 = "A3";
          ligne.ligneHT2 = "08";
          ligne.ligneTVA1 = "20";
        } else if (natureOperation === "Immobilisation") {
          ligne.ligneHT1 = "A4";
          ligne.ligneHT2 = "I1";
          ligne.ligneTVA1 = "19";
        }
    } else {
      if (natureOperation === "Immobilisation") {
        ligne.ligneTVA1 = "19";
      } else if (date >= moisAnneeCibleDebut) {
        ligne.ligneTVA1 = "20";
      } else {
        ligne.ligneTVA1 = "21";
      }
    }
  }
  return ligne;
}

function genererDeclarationBRC() {
  const ui = SpreadsheetApp.getUi();
  const response = ui.prompt("Saisis le mois et l'année de déclaration BRC (ex: Novembre 2025)", ui.ButtonSet.OK_CANCEL);

  if (response.getSelectedButton() !== ui.Button.OK) return;
  const moisAnneeCible = response.getResponseText();

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const feuilleSource = ss.getSheetByName("BV & RM"); 

  const modeleFileId = ID_TEMPLATE_BRC;
  const dossierId = ID_DOSSIER_BRC;
  const nomNouveauFichier = `BRC ${moisAnneeCible}`;

  const modele = DriveApp.getFileById(modeleFileId);
  const dossier = DriveApp.getFolderById(dossierId);
  const copie = modele.makeCopy(nomNouveauFichier, dossier);
  const newSs = SpreadsheetApp.openById(copie.getId());

  const recapBV = newSs.getSheetByName("Recap BV");

  remplirRecapBV(feuilleSource, recapBV, moisAnneeCible);
  insererChipFichier(moisAnneeCible, copie, 7); // colonne G = 7

  ui.alert("Fichier BRC généré avec succès : " + nomNouveauFichier);
}

function remplirRecapBV(sourceSheet, targetSheet, moisAnneeCible) {
  const lastRow = sourceSheet.getLastRow();
  if (lastRow < 8) return; 

  // On récupère de la colonne A (1) jusqu'à la colonne Y (25)
  // Cela permet d'avoir toutes les colonnes nécessaires dans le tableau 'donnees'
  const donnees = sourceSheet.getRange(8, 1, lastRow - 7, 25).getValues(); 

  const numeroMois = {
    "Janvier": 0, "Février": 1, "Mars": 2, "Avril": 3, "Mai": 4, "Juin": 5,
    "Juillet": 6, "Août": 7, "Septembre": 8, "Octobre": 9, "Novembre": 10, "Décembre": 11
  };

  const parts = moisAnneeCible.split(" ");
  if (parts.length < 2) {
    SpreadsheetApp.getUi().alert("Format de date invalide. Utilisez 'Mois Année' (ex: Mai 2025).");
    return;
  }

  const moisNom = parts[0];
  const annee = parseInt(parts[1], 10);
  const moisIndex = numeroMois[moisNom];

  if (moisIndex === undefined) {
    SpreadsheetApp.getUi().alert("Mois inconnu.");
    return;
  }

  const lignesADeclarer = [];

  for (const ligne of donnees) {
    // CORRESPONDANCE DES COLONNES (Index 0 = Colonne A)
    // B = 1, C = 2, D = 3, I = 8, K = 10, V = 21, W = 22, X = 23, Y = 24

    const numBV = ligne[1];     // Col B

    // On vérifie s'il y a un N° BV, sinon on passe
    if (!numBV) continue; 

    let rawDate = ligne[3];     // Col D: Date émission
    let dateEmission;

    if (rawDate instanceof Date) {
      dateEmission = rawDate;
    } else if (typeof rawDate === 'string' && rawDate !== "") {
      dateEmission = new Date(rawDate);
    } else {
      continue; 
    }

    // Filtre sur le mois et l'année
    if (dateEmission.getMonth() === moisIndex && dateEmission.getFullYear() === annee) {

      const nomPrenom = ligne[10];      // Col K: Nom Prenom
      const retriBrute = ligne[8];      // Col I: Rétri. brute
      const tauxAM = ligne[21];         // Col V: Taux AM
      const tauxAT = ligne[22];         // Col W: Taux AT
      const baseUrssaf = ligne[23];     // Col X: BASE URSSAF
      const assietteCotis = ligne[24];  // Col Y: Assiette cotisation

      // Ajout au tableau final
      lignesADeclarer.push([
        numBV,
        nomPrenom,
        dateEmission,
        retriBrute,
        tauxAM,
        tauxAT,
        baseUrssaf,
        assietteCotis
      ]);
    }
  }

  if (lignesADeclarer.length > 0) {
    targetSheet.getRange(2, 1, lignesADeclarer.length, lignesADeclarer[0].length).setValues(lignesADeclarer);
  } else {
    SpreadsheetApp.getUi().alert("Aucune donnée trouvée pour " + moisAnneeCible);
  }
}

const SHEET_NAME = 'Suivi des études';

function genererSheetFacturation() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);

  if (!sheet) {
    SpreadsheetApp.getUi().alert(`La feuille "${SHEET_NAME}" est introuvable.`);
    return;
  }

  // Récupération de toutes les données (à partir de la ligne 3 pour ignorer l'en-tête)
  // On récupère tout le range pour optimiser les lectures
  const firstRow = 3;
  const lastRow = sheet.getLastRow();
  if (lastRow < firstRow) return; // Pas de données

  const dataRange = sheet.getRange(firstRow, 1, lastRow - 1, 10); // Colonnes A à J
  const data = dataRange.getValues();

  let erreurs = [];
  let feuillesCreees = 0;

  // Indices des colonnes (Base 0 pour le tableau data)
  // A=0, F=5, G=6, H=7, J=9
  const COL_A_INDEX = 0; // Numéro étude
  const COL_F_INDEX = 5; // Nom étude
  const COL_G_INDEX = 6; // Lien Facturation
  const COL_H_INDEX = 7; // Case à cocher
  const COL_J_INDEX = 9; // Date signature

  // Initialisation des services Drive
  const templateFile = DriveApp.getFileById(ID_TEMPLATE_SHEET_FACT);
  const targetFolder = DriveApp.getFolderById(ID_DOSSIER_SHEETS_FACT);

  for (let i = 0; i < data.length; i++) {
    let row = data[i];
    let rowIndex = i + firstRow; // Numéro de ligne réel dans le Sheet

    // Condition principale : H est coché (TRUE)
    if (row[COL_H_INDEX] === true) {

      let erreursLigne = [];

      // Vérification des conditions bloquantes
      if (row[COL_G_INDEX] !== "") erreursLigne.push("Colonne G n'est pas vide");
      if (!row[COL_F_INDEX]) erreursLigne.push("Colonne F (Nom) est vide");
      if (!row[COL_A_INDEX]) erreursLigne.push("Colonne A (Numéro) est vide");
      if (!row[COL_J_INDEX]) erreursLigne.push("Colonne J (Date) est vide");

      if (erreursLigne.length > 0) {
        // Enregistrement de l'erreur
        erreurs.push(`Ligne ${rowIndex} : ${erreursLigne.join(', ')}`);
      } else {
        // Tout est bon, on génère le sheet
        try {
          let numEtude = row[COL_A_INDEX];
          let nomEtude = row[COL_F_INDEX];
          let nouveauNom = `${numEtude} ${nomEtude}`;

          // Copie du fichier
          let nouveauFichier = templateFile.makeCopy(nouveauNom, targetFolder);
          let fileUrl = nouveauFichier.getUrl();

          // Mise à jour du Sheet : Lien en G + Décocher H
          sheet.getRange(rowIndex, COL_G_INDEX + 1).setValue(fileUrl);
          sheet.getRange(rowIndex, COL_H_INDEX + 1).uncheck();

          feuillesCreees++;

        } catch (e) {
          erreurs.push(`Ligne ${rowIndex} : Erreur système (${e.message})`);
        }
      }
    }
  }

  // Feedback à l'utilisateur
  let message = `${feuillesCreees} sheet(s) de facturation généré(s).`;
  if (erreurs.length > 0) {
    message += `\n\nErreurs rencontrées :\n` + erreurs.join('\n');
    SpreadsheetApp.getUi().alert(message);
  } else if (feuillesCreees > 0) {
    SpreadsheetApp.getUi().alert(message);
  }
}

