function insererChipFichier(moisAnneeCible, fichier, colonne) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const feuilleDecla = ss.getSheetByName("Déclaratifs mensuels");
  const colMois = feuilleDecla.getRange("A:A").getValues();

  let ligneTarget = -1;
  for (let i = 0; i < colMois.length; i++) {
    if (colMois[i][0].toString().trim().toLowerCase() === moisAnneeCible.trim().toLowerCase()) {
      ligneTarget = i + 1;
      break;
    }
  }

  if (ligneTarget === -1) {
    SpreadsheetApp.getUi().alert(`Mois "${moisAnneeCible}" introuvable dans 'Déclaratifs mensuels'.`);
    return;
  }

  let fileUrl = fichier.getUrl();
  feuilleDecla.getRange(ligneTarget, colonne).setValue(fileUrl);
}

/**
 * RemiseAZero.gs
 *
 * Cree une COPIE du Tableau de Suivi dans le meme dossier Drive
 * et remet cette COPIE a zero en preservant :
 *   - les formules
 *   - la mise en forme et les bordures
 *   - les regles de validation de donnees (dropdowns, cases a cocher)
 *
 * Le fichier ORIGINAL reste intact (il sert d'archive de l'annee ecoulee).
 * La COPIE devient le nouveau TS vierge pour l'annee suivante.
 *
 * Feuilles protegees dans la copie (non touchees) :
 *   Introduction, Mode d'emploi, Pays, Dashboard, Parametrage,
 *   Taux cotisations, KPIs
 *
 * Dans chaque feuille, les lignes et colonnes gelees sont preservees
 * (elles contiennent les en-tetes). Seule la zone de donnees est videe.
 */

// ── Configuration ─────────────────────────────────────────────────────────────

const FEUILLES_PROTEGEES = [
  'Introduction',
  "Mode d'emploi",
  'Pays',
  'Dashboard',
  'Paramétrage',
  'Taux cotisations',
  'KPIs',
  'TVA_Etrange',
  'Indicateurs qualité',
  'Cut-off',
  'TVA',
  'URSSAF',
  'Datas',
  'Datas_VT_Tiers',
  'Datas_VT_Etudes_Clients',
  'Datas_suivi_etudes',
];

// ── Fonction principale ───────────────────────────────────────────────────────

function remiseAZero() {
  const ui = SpreadsheetApp.getUi();
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  const rep = ui.alert(
    'Creer un nouveau TS vierge',
    'Cette action va :\n\n'
      + '1. Creer une copie du TS actuel dans le meme dossier Drive\n'
      + '   (le fichier original reste intact : il devient l\'archive)\n'
      + '2. Vider les donnees saisies dans la COPIE\n'
      + '   (formules, en-tetes, mise en forme et validations conserves)\n\n'
      + 'Continuer ?',
    ui.ButtonSet.YES_NO
  );
  if (rep !== ui.Button.YES) return;

  // Etape 1 : creer la copie
  let copie;
  try {
    copie = _creerCopie(ss);
  } catch (e) {
    ui.alert('Erreur lors de la creation de la copie', e.message, ui.ButtonSet.OK);
    return;
  }

  // Etape 2 : ouvrir la copie et nettoyer ses feuilles de donnees
  const ssCopie = SpreadsheetApp.openById(copie.getId());
  const rapport = [];

  for (const sheet of ssCopie.getSheets()) {
    const nom = sheet.getName();
    if (FEUILLES_PROTEGEES.includes(nom)) {
      rapport.push('  (ignoree) ' + nom);
      continue;
    }
    try {
      _nettoyerFeuille(sheet);
      rapport.push('  OK  ' + nom);
    } catch (e) {
      rapport.push('  ERR ' + nom + ' : ' + e.message);
    }
  }

  ui.alert(
    'Nouveau TS vierge cree',
    'Fichier cree : ' + copie.getName() + '\n'
      + copie.getUrl() + '\n\n'
      + 'Le fichier original est conserve tel quel (archive).\n\n'
      + 'Feuilles traitees dans la copie :\n' + rapport.join('\n'),
    ui.ButtonSet.OK
  );
}

// ── Creation de la copie ──────────────────────────────────────────────────────

function _creerCopie(ss) {
  const dateTag  = Utilities.formatDate(new Date(), 'Europe/Paris', 'yyyy-MM-dd');
  const nomCopie = ss.getName() + '_Vierge_' + dateTag;
  const dossier  = DriveApp.getFileById(ss.getId()).getParents().next();
  return DriveApp.getFileById(ss.getId()).makeCopy(nomCopie, dossier);
}

// ── Nettoyage d'une feuille de la copie ──────────────────────────────────────

function _nettoyerFeuille(sheet) {
  const lastRow = sheet.getLastRow();
  const lastCol = sheet.getLastColumn();

  // Lignes et colonnes gelees = en-tetes a conserver
  // getFrozenRows() et getFrozenColumns() sont des methodes natives Apps Script
  const frozenRows = sheet.getFrozenRows();
  const frozenCols = sheet.getFrozenColumns();

  const firstDataRow = frozenRows + 1;
  const firstDataCol = (sheet.getName() === 'Budget' || sheet.getName() === 'Suivi Disponibilités') ? frozenCols + 1 : 0;

  // Rien a effacer si la zone de donnees est vide
  if (lastRow < firstDataRow || lastCol < firstDataCol) return;

  const nbRows = lastRow - firstDataRow + 1;
  const nbCols = lastCol - firstDataCol + 1;

  if (nbRows <= 0 || nbCols <= 0) return;

  const range = sheet.getRange(firstDataRow, firstDataCol, nbRows, nbCols);

  // Lecture groupee : formules et validations
  const formulas    = range.getFormulas();
  const validations = range.getDataValidations();

  // Reperer les cases a cocher dans la zone de donnees
  const checkboxes = [];
  for (let r = 0; r < nbRows; r++) {
    for (let c = 0; c < nbCols; c++) {
      const rule = validations[r][c];
      if (rule && rule.getCriteriaType().toString() === 'CHECKBOX') {
        checkboxes.push([firstDataRow + r, firstDataCol + c]);
      }
    }
  }

  // Effacer le contenu (conserve mise en forme, bordures et validations)
  range.clearContent();

  // Restaurer les formules en une seule ecriture groupee
  range.setFormulas(formulas);

  // Reinitialiser les cases a cocher a FALSE
  for (const [row, col] of checkboxes) {
    sheet.getRange(row, col).setValue(false);
  }

  // Reinitialiser les criteres de filtre actifs sans supprimer le filtre
  const filter = sheet.getFilter();
  if (filter) {
    const nbColsFiltres = filter.getRange().getNumColumns();
    for (let c = 1; c <= nbColsFiltres; c++) {
      try { filter.removeColumnFilterCriteria(c); } catch (_) {}
    }
  }
}

